#include<bits/stdc++.h>
using namespace std;
int n,m[10005],ans[1005],dp[1005][1005];
int main(){

    cin>>n;
    for(int i=1;i<=n;i++) cin>>m[i];

    for(int i=1;i<=n;i++) ans[i]=ans[i-1]+m[i];

    for(int len=2;len<=n;len++){
        for(int i=0;i+len-1<n;i++){
            int j=i-1+len;
            dp[i][j]=INT_MAX;
            for(int k=i;k<=j;k++){
                dp[i][j]=min(dp[i][k]+dp[k+1][j],dp[i][j]);
            }
            dp[i][j]+=(ans[j+1]-ans[i]);
        }
    }
    cout<<dp[0][n-1];
    return 0;
}
